#!/bin/bash
# Spyre vLLM Benchmark Runner
#
# Reads JSON test configs (generated by generate_test_configs.py) and runs
# vLLM benchmarks. Supports parallel execution across multiple Spyre devices
# using device isolation (SPYRE_DEVICES + AIU_WORLD_SIZE per process).
#
# Parallelism: When multiple Spyre cards are available (AIU_WORLD_SIZE > 1),
# different models run concurrently on separate devices.

set -eo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(dirname "$SCRIPT_DIR")"
RESULTS_DIR="${RESULTS_DIR:-$REPO_ROOT/results}"
CONFIG_FILE="${CONFIG_FILE:-$REPO_ROOT/config/benchmark_config.yaml}"
TIMESTAMP=$(date -u +"%Y%m%dT%H%M%SZ")
NUM_DEVICES="${AIU_WORLD_SIZE:-1}"

mkdir -p "$RESULTS_DIR"

# -----------------------------------------------
# Detect benchmark CLI
# -----------------------------------------------
detect_bench_command() {
    if vllm bench --help &>/dev/null; then
        BENCH_CMD="vllm bench"
    elif python3 -m vllm.entrypoints.cli.main bench --help &>/dev/null; then
        BENCH_CMD="python3 -m vllm.entrypoints.cli.main bench"
    else
        BENCH_CMD=""
    fi
    echo "  Bench CLI: ${BENCH_CMD:-LEGACY FALLBACK}"
}

# -----------------------------------------------
# json2args: convert JSON params to CLI args
# -----------------------------------------------
json2args() {
    local json_string=$1
    echo "$json_string" | jq -r '
        to_entries |
        map(
            if .value == true then "--" + (.key | gsub("_"; "-"))
            elif .value == false then ""
            else "--" + (.key | gsub("_"; "-")) + " " + (.value | tostring)
            end
        ) |
        map(select(. != "")) |
        join(" ")
    '
}

# -----------------------------------------------
# Run a single offline benchmark (latency/throughput) on a specific device
# -----------------------------------------------
run_single_test() {
    local test_type=$1
    local test_name=$2
    local bench_args=$3
    local device_id=${4:-0}
    local tp_size=${5:-1}

    # Calculate device range for TP>1
    local spyre_devices="$device_id"
    if [[ $tp_size -gt 1 ]]; then
        local devices=()
        for ((d=device_id; d<device_id+tp_size; d++)); do
            devices+=("$d")
        done
        spyre_devices=$(IFS=,; echo "${devices[*]}")
    fi

    echo ""
    echo "┌─ [$test_type] $test_name (devices: $spyre_devices, tp: $tp_size)"

    local bench_command
    if [[ -n "$BENCH_CMD" ]]; then
        bench_command="$BENCH_CMD $test_type --output-json $RESULTS_DIR/${test_name}.json $bench_args"
    else
        if [[ "$test_type" == "latency" ]]; then
            bench_command="python3 -m vllm.benchmarks.latency --output-json $RESULTS_DIR/${test_name}.json $bench_args"
        elif [[ "$test_type" == "throughput" ]]; then
            bench_command="python3 -m vllm.benchmarks.throughput --output-json $RESULTS_DIR/${test_name}.json $bench_args"
        fi
    fi

    echo "│ Command: $bench_command"
    echo "│ Env: SPYRE_DEVICES=$spyre_devices AIU_WORLD_SIZE=$tp_size"
    echo "│"

    jq -n \
        --arg command "$bench_command" \
        --arg device "spyre:$spyre_devices" \
        --arg timestamp "$TIMESTAMP" \
        '{command: $command, device: $device, timestamp: $timestamp}' \
        > "$RESULTS_DIR/${test_name}.commands"

    # Run with device isolation
    if SPYRE_DEVICES=$spyre_devices AIU_WORLD_SIZE=$tp_size LOCAL_RANK=0 \
        eval "$bench_command" 2>&1; then
        if [[ -f "$RESULTS_DIR/${test_name}.json" ]]; then
            echo "│"
            if [[ "$test_type" == "latency" ]]; then
                echo "│ Result: $(jq -r '"avg=\(.avg_latency | tostring | .[0:6])s  p50=\(.percentiles."50" | tostring | .[0:6])s  p99=\(.percentiles."99" | tostring | .[0:6])s"' "$RESULTS_DIR/${test_name}.json" 2>/dev/null || echo "see JSON")"
            elif [[ "$test_type" == "throughput" ]]; then
                echo "│ Result: $(jq -r '"\(.tokens_per_second | tostring | .[0:7]) tok/s  \(.requests_per_second | tostring | .[0:5]) req/s  \(.elapsed_time | tostring | .[0:6])s elapsed"' "$RESULTS_DIR/${test_name}.json" 2>/dev/null || echo "see JSON")"
            fi
        fi
        echo "└─ PASS"
        return 0
    else
        echo "└─ FAIL (exit code: $?)"
        return 1
    fi
}

# -----------------------------------------------
# Run all tests for a model on a specific device (sequential within model)
# Called as a background job for parallel mode
# -----------------------------------------------
run_model_on_device() {
    local model=$1
    local device_id=$2
    local latency_file=$3
    local throughput_file=$4
    local log_file="$RESULTS_DIR/device_${device_id}_${model//\//_}.log"

    echo ""
    echo "╔════════════════════════════════════════════╗"
    echo "║  MODEL: $model (device: $device_id)"
    echo "╚════════════════════════════════════════════╝"

    local pass_count=0
    local fail_count=0

    # Latency tests for this model
    if [[ -f "$latency_file" ]]; then
        while read -r params; do
            local test_name
            test_name=$(echo "$params" | jq -r '.test_name')
            local bench_params
            bench_params=$(echo "$params" | jq -r '.parameters')
            local tp_size
            tp_size=$(echo "$bench_params" | jq -r '.tensor_parallel_size // 1')
            local bench_args
            bench_args=$(json2args "$bench_params")

            if run_single_test "latency" "$test_name" "$bench_args" "$device_id" "$tp_size"; then
                pass_count=$((pass_count + 1))
            else
                fail_count=$((fail_count + 1))
            fi
        done < <(jq -c --arg model "$model" '.[] | select(.parameters.model == $model)' "$latency_file")
    fi

    # Throughput tests for this model
    if [[ -f "$throughput_file" ]]; then
        while read -r params; do
            local test_name
            test_name=$(echo "$params" | jq -r '.test_name')
            local bench_params
            bench_params=$(echo "$params" | jq -r '.parameters')
            local tp_size
            tp_size=$(echo "$bench_params" | jq -r '.tensor_parallel_size // 1')
            local bench_args
            bench_args=$(json2args "$bench_params")

            if run_single_test "throughput" "$test_name" "$bench_args" "$device_id" "$tp_size"; then
                pass_count=$((pass_count + 1))
            else
                fail_count=$((fail_count + 1))
            fi
        done < <(jq -c --arg model "$model" '.[] | select(.parameters.model == $model)' "$throughput_file")
    fi

    echo ""
    echo "  [$model] device $device_id: $pass_count passed, $fail_count failed"
    return $fail_count
}

# -----------------------------------------------
# Run offline benchmarks sequentially (single device)
# -----------------------------------------------
run_benchmark_tests() {
    local test_type=$1
    local test_file=$2
    local pass_count=0
    local fail_count=0

    if [[ ! -f "$test_file" ]]; then
        echo "  WARNING: Test file not found: $test_file"
        return 1
    fi

    local total
    total=$(jq '. | length' "$test_file")

    echo ""
    echo "╔════════════════════════════════════════════╗"
    echo "║  ${test_type^^} BENCHMARKS ($total tests)"
    echo "╚════════════════════════════════════════════╝"

    while read -r params; do
        local test_name
        test_name=$(echo "$params" | jq -r '.test_name')
        local bench_params
        bench_params=$(echo "$params" | jq -r '.parameters')
        local tp_size
        tp_size=$(echo "$bench_params" | jq -r '.tensor_parallel_size // 1')
        local bench_args
        bench_args=$(json2args "$bench_params")

        if run_single_test "$test_type" "$test_name" "$bench_args" "0" "$tp_size"; then
            pass_count=$((pass_count + 1))
        else
            fail_count=$((fail_count + 1))
        fi
    done < <(jq -c '.[]' "$test_file")

    echo ""
    echo "  ${test_type} result: $pass_count passed, $fail_count failed (of $total)"
}

# -----------------------------------------------
# Run serve benchmarks (starts server per model on specific device)
# -----------------------------------------------
run_serve_benchmarks() {
    local test_file=$1
    local device_id=${2:-0}
    local pass_count=0
    local fail_count=0
    local total
    local current_model=""
    local server_pid=""

    total=$(jq '. | length' "$test_file")

    echo ""
    echo "╔════════════════════════════════════════════╗"
    echo "║  SERVE BENCHMARKS ($total tests, device: $device_id)"
    echo "╚════════════════════════════════════════════╝"

    while read -r test_config; do
        local test_name
        test_name=$(echo "$test_config" | jq -r '.test_name')
        local server_params
        server_params=$(echo "$test_config" | jq -r '.server_parameters')
        local client_params
        client_params=$(echo "$test_config" | jq -r '.client_parameters')
        local model
        model=$(echo "$server_params" | jq -r '.model')

        # Start/restart server if model changed
        if [[ "$model" != "$current_model" ]]; then
            if [[ -n "$server_pid" ]]; then
                echo "│ Stopping server (pid=$server_pid)..."
                kill "$server_pid" 2>/dev/null || true
                wait "$server_pid" 2>/dev/null || true
                server_pid=""
            fi

            current_model="$model"
            local tp_size
            tp_size=$(echo "$server_params" | jq -r '.tensor_parallel_size // 1')

            # Calculate device range for serve
            local spyre_devices="$device_id"
            if [[ $tp_size -gt 1 ]]; then
                local devices=()
                for ((d=device_id; d<device_id+tp_size; d++)); do
                    devices+=("$d")
                done
                spyre_devices=$(IFS=,; echo "${devices[*]}")
            fi

            echo ""
            echo "┌─ [serve] Starting vLLM server: $model (devices: $spyre_devices, tp: $tp_size)"
            echo "│"

            # Start server with device isolation
            SPYRE_DEVICES=$spyre_devices AIU_WORLD_SIZE=$tp_size LOCAL_RANK=0 \
                vllm serve "$model" \
                --dtype $(echo "$server_params" | jq -r '.dtype') \
                --max-model-len $(echo "$server_params" | jq -r '.max_model_len') \
                --load-format $(echo "$server_params" | jq -r '.load_format') \
                --tensor-parallel-size "$tp_size" \
                --port 8000 \
                > "$RESULTS_DIR/server_${test_name}.log" 2>&1 &
            server_pid=$!

            echo "│ Waiting for server to be ready..."
            local retries=0
            local max_retries=180
            while [[ $retries -lt $max_retries ]]; do
                if curl -s http://localhost:8000/health > /dev/null 2>&1; then
                    echo "│ Server ready (took ${retries}s)"
                    break
                fi
                if ! kill -0 "$server_pid" 2>/dev/null; then
                    echo "│ Server process died!"
                    echo "└─ FAIL (server crashed)"
                    fail_count=$((fail_count + total))
                    server_pid=""
                    break 2
                fi
                sleep 1
                retries=$((retries + 1))
            done

            if [[ $retries -ge $max_retries ]]; then
                echo "│ Server failed to start within ${max_retries}s"
                echo "└─ FAIL (server timeout)"
                kill "$server_pid" 2>/dev/null || true
                server_pid=""
                continue
            fi
        fi

        # Run client benchmark (client doesn't use Spyre directly)
        echo ""
        echo "┌─ [serve] $test_name"
        local client_args
        client_args=$(json2args "$client_params")
        local result_dir="$RESULTS_DIR/serve_results"
        mkdir -p "$result_dir"
        local bench_command="$BENCH_CMD serve --save-result --result-dir $result_dir --result-filename ${test_name}.json $client_args"
        echo "│ Command: $bench_command"
        echo "│"

        jq -n \
            --arg command "$bench_command" \
            --arg device "spyre:$device_id" \
            --arg timestamp "$TIMESTAMP" \
            '{command: $command, device: $device, timestamp: $timestamp}' \
            > "$RESULTS_DIR/${test_name}.commands"

        if eval "$bench_command" 2>&1; then
            local result_file="$result_dir/${test_name}.json"
            if [[ -f "$result_file" ]]; then
                cp "$result_file" "$RESULTS_DIR/${test_name}.json"
                echo "│"
                echo "│ Result: $(jq -r '"TTFT_p50=\(.median_ttft_ms // "N/A")ms  TPOT_p50=\(.median_tpot_ms // "N/A")ms  throughput=\(.output_throughput // .request_throughput // "N/A") tok/s"' "$result_file" 2>/dev/null || echo "see JSON")"
            fi
            echo "└─ PASS"
            pass_count=$((pass_count + 1))
        else
            echo "└─ FAIL (exit code: $?)"
            fail_count=$((fail_count + 1))
        fi
    done < <(jq -c '.[]' "$test_file")

    if [[ -n "$server_pid" ]]; then
        echo ""
        echo "  Stopping server (pid=$server_pid)..."
        kill "$server_pid" 2>/dev/null || true
        wait "$server_pid" 2>/dev/null || true
    fi

    echo ""
    echo "  serve result: $pass_count passed, $fail_count failed (of $total)"
}

# -----------------------------------------------
# Main
# -----------------------------------------------
main() {
    echo ""
    echo "=========================================="
    echo "  Spyre vLLM Benchmark Suite"
    echo "  Timestamp: $TIMESTAMP"
    echo "  Devices:   $NUM_DEVICES"
    echo "=========================================="

    if ! command -v jq &>/dev/null; then
        echo "ERROR: jq is required but not found."
        exit 1
    fi

    detect_bench_command

    # Step 1: Generate test configs
    echo ""
    echo "=== Generating test configurations ==="
    python3 "$SCRIPT_DIR/generate_test_configs.py" "$CONFIG_FILE" "$RESULTS_DIR"

    local latency_file="$RESULTS_DIR/latency-tests.json"
    local throughput_file="$RESULTS_DIR/throughput-tests.json"
    local serve_file="$RESULTS_DIR/serve-tests.json"

    # Step 2: Run offline benchmarks (latency + throughput)
    if [[ $NUM_DEVICES -gt 1 ]]; then
        # Multi-device: run models in parallel on separate devices
        local models=()
        if [[ -f "$latency_file" ]]; then
            while IFS= read -r m; do models+=("$m"); done < <(jq -r '.[].parameters.model' "$latency_file" | sort -u)
        fi
        if [[ -f "$throughput_file" ]]; then
            while IFS= read -r m; do
                local found=false
                for existing in "${models[@]:-}"; do [[ "$existing" == "$m" ]] && found=true && break; done
                [[ "$found" == "false" ]] && models+=("$m")
            done < <(jq -r '.[].parameters.model' "$throughput_file" | sort -u)
        fi

        local num_models=${#models[@]}
        echo ""
        echo "=== Parallel mode: $num_models model(s) on $NUM_DEVICES device(s) ==="
        for i in "${!models[@]}"; do
            echo "  - ${models[$i]} → device $((i % NUM_DEVICES))"
        done

        if [[ $num_models -le 1 ]]; then
            # Single model — run sequentially on device 0
            [[ -f "$latency_file" ]] && run_benchmark_tests "latency" "$latency_file"
            [[ -f "$throughput_file" ]] && run_benchmark_tests "throughput" "$throughput_file"
        else
            # Launch models in parallel, each on its own device
            local pids=()
            local log_files=()

            for i in "${!models[@]}"; do
                local device_id=$((i % NUM_DEVICES))
                local model="${models[$i]}"
                local safe_name="${model//\//_}"
                local model_log="$RESULTS_DIR/parallel_${safe_name}.log"
                log_files+=("$model_log")

                echo "  Launching: $model on device $device_id"
                run_model_on_device "$model" "$device_id" "$latency_file" "$throughput_file" > "$model_log" 2>&1 &
                pids+=($!)
            done

            echo ""
            echo "=== Waiting for parallel jobs ==="
            for i in "${!pids[@]}"; do
                if wait "${pids[$i]}"; then
                    echo "  DONE: ${models[$i]} (device $((i % NUM_DEVICES)))"
                else
                    echo "  DONE (with failures): ${models[$i]}"
                fi
            done

            # Print logs to stdout
            echo ""
            echo "=== Parallel execution logs ==="
            for log_file in "${log_files[@]}"; do
                [[ -f "$log_file" ]] && cat "$log_file"
            done
        fi
    else
        # Single device: sequential execution
        [[ -f "$latency_file" ]] && run_benchmark_tests "latency" "$latency_file"
        [[ -f "$throughput_file" ]] && run_benchmark_tests "throughput" "$throughput_file"
    fi

    # Step 3: Run serve benchmarks (always sequential — server needs the port)
    if [[ -f "$serve_file" ]]; then
        local serve_count
        serve_count=$(jq '. | length' "$serve_file")
        if [[ "$serve_count" -gt 0 ]]; then
            run_serve_benchmarks "$serve_file" "0"
        fi
    fi

    # Step 4: Collect and summarize results
    echo ""
    echo "=== Collecting results ==="
    python3 "$SCRIPT_DIR/collect_results.py" "$RESULTS_DIR" "$TIMESTAMP" || echo "WARNING: collect_results.py failed (results still available as individual JSONs)"

    # Step 5: Print results to stdout for log capture
    echo ""
    echo "========== BENCHMARK RESULTS (JSON) =========="
    if [[ -f "$RESULTS_DIR/benchmark_summary.json" ]]; then
        cat "$RESULTS_DIR/benchmark_summary.json"
    else
        echo "{\"error\": \"No summary generated\"}"
    fi
    echo ""
    echo "========== END BENCHMARK RESULTS =========="

    # Print individual result JSONs
    for f in "$RESULTS_DIR"/*.json; do
        local basename_f
        basename_f=$(basename "$f")
        [[ "$basename_f" == *-tests.json ]] && continue
        [[ "$basename_f" == "benchmark_summary.json" ]] && continue
        [[ "$basename_f" == *.pytorch.json ]] && continue
        echo ""
        echo "--- $basename_f ---"
        cat "$f"
    done

    # Print pytorch JSONs (model name extraction)
    for f in "$RESULTS_DIR"/*.pytorch.json; do
        [[ -f "$f" ]] || continue
        local basename_f
        basename_f=$(basename "$f")
        echo ""
        echo "--- $basename_f ---"
        cat "$f"
    done

    echo ""
    echo "=========================================="
    echo "  Benchmark run complete: $TIMESTAMP"
    echo "=========================================="
}

main "$@"
